#include <bits/stdc++.h>
using namespace std;
void heapify_max(vector<int>& nums, int n, int i) {
    int largest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;
    if (left < n && nums[left] > nums[largest])
        largest = left;
    if (right < n && nums[right] > nums[largest])
        largest = right;
    if (largest != i) {
        swap(nums[i], nums[largest]);
        heapify_max(nums, n, largest);
    }
}
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    for (int i = n / 2 - 1; i >= 0; i--)
        heapify_max(nums, n, i);
    cout << n << '\n';
    for (int num : nums)
        cout << num << ' ';
    return 0;
}
